create extension if not exists citext with schema public; create table if not exists public.profiles (id uuid); do $$ begin if not exists (select 1 from pg_constraint where conrelid = 'public.profiles'::regclass and contype = 'p') then alter table public.profiles add constraint profiles_pkey primary key (id); end if; if exists (select 1 from pg_constraint where conrelid = 'public.profiles'::regclass and conname='profiles_id_fkey') then alter table public.profiles drop constraint profiles_id_fkey; end if; alter table public.profiles add constraint profiles_id_fkey foreign key (id) references auth.users(id) on delete cascade not valid; exception when others then null; end $$; alter table public.profiles add column if not exists email citext, add column if not exists full_name text, add column if not exists avatar_url text, add column if not exists email_confirmed_at timestamptz, add column if not exists last_sign_in_at timestamptz, add column if not exists created_at timestamptz, add column if not exists updated_at timestamptz; update public.profiles set created_at = coalesce(created_at, now()), updated_at = coalesce(updated_at, now()); alter table public.profiles alter column created_at set not null, alter column created_at set default now(), alter column updated_at set not null, alter column updated_at set default now(); alter table public.profiles enable row level security; revoke all on public.profiles from anon, authenticated; grant select on public.profiles to authenticated; create index if not exists idx_profiles_email on public.profiles (email); drop policy if exists "profiles_select_self" on public.profiles; create policy "profiles_select_self" on public.profiles for select to authenticated using (id = auth.uid()); drop policy if exists "profiles_select_same_company" on public.profiles; create policy "profiles_select_same_company" on public.profiles for select to authenticated using ( exists ( select 1 from public.company_members me join public.company_members them on me.company_id = them.company_id where me.user_id = auth.uid() and them.user_id = profiles.id ) ); create or replace function public.handle_user_profile_sync() returns trigger language plpgsql security definer set search_path = public as $$ begin insert into public.profiles (id, email, full_name, avatar_url, email_confirmed_at, last_sign_in_at, created_at, updated_at) values ( new.id, new.email, coalesce(new.raw_user_meta_data->>'full_name', null), coalesce(new.raw_user_meta_data->>'avatar_url', null), new.email_confirmed_at, new.last_sign_in_at, now(), now() ) on conflict (id) do update set email = excluded.email, full_name = excluded.full_name, avatar_url = excluded.avatar_url, email_confirmed_at = excluded.email_confirmed_at, last_sign_in_at = excluded.last_sign_in_at, updated_at = now(); return new; end; $$; drop trigger if exists trg_auth_users_profile_ins on auth.users; create trigger trg_auth_users_profile_ins after insert on auth.users for each row execute function public.handle_user_profile_sync(); drop trigger if exists trg_auth_users_profile_upd on auth.users; create trigger trg_auth_users_profile_upd after update of email, raw_user_meta_data, email_confirmed_at, last_sign_in_at on auth.users for each row execute function public.handle_user_profile_sync();;
